package main

import (
	"bytes"
	"context"
	"os"
	"testing"

	"github.com/aquasecurity/fanal/analyzer"
	dio "github.com/aquasecurity/go-dep-parser/pkg/io"
	ftypes "github.com/aquasecurity/fanal/types"
	"golang.org/x/sync/semaphore"

	"github.com/future-architect/vuls/config"
	"github.com/future-architect/vuls/models"
	"github.com/future-architect/vuls/scanner"
)

// TestRegression tests all four library scanning failure issues
func TestRegression(t *testing.T) {
	t.Run("PNPM_Ecosystem_Not_Supported", testPnpmEcosystemNotSupported)
	t.Run("Trivy_DB_Client_Init_Fails", testTrivyDBClientInitFailure)
	t.Run("Missing_PNPM_In_Library_Map", testMissingPnpmInLibraryMap)
	t.Run("Incomplete_Scan_Scope_Control", testIncompleteScanScopeControl)
}

// testPnpmEcosystemNotSupported verifies that PNPM lockfiles are not recognized
func testPnpmEcosystemNotSupported(t *testing.T) {
	// Create a sample pnpm-lock.yaml content
	pnpmLockContent := []byte(`lockfileVersion: 5.4
requires: true
packages:
  lodash:
    version: 4.17.21
    resolved: https://registry.npmjs.org/lodash/-/lodash-4.17.21.tgz
    integrity: sha512-v2kDEe57lecTulaDIuNTPy3Ry4gLGJ6Z1O3vE1krgXZNrsQ+LFTGHVxVjcXPs17LhbZVGedAJv8XcmC2HB+9A==`)

	libFilemap := map[string]scanner.LibFile{
		"pnpm-lock.yaml": {
			Contents: pnpmLockContent,
			Filemode: 0644,
		},
	}

	// Try to analyze PNPM lockfile
	libraryScanners, err := scanner.AnalyzeLibraries(context.Background(), libFilemap, false)

	// PNPM should not be recognized - either:
	// 1. No libraries detected (PNPM not supported)
	// 2. Error returned because PNPM analyzer not available
	if err != nil {
		// Expected: Error because PNPM ecosystem is not supported
		t.Logf("Got expected error for PNPM: %v", err)
	} else if len(libraryScanners) == 0 {
		// Also acceptable - PNPM not recognized so no results
		t.Logf("PNPM lockfile not recognized - no libraries detected")
	} else {
		// This would indicate PNPM is actually supported
		// Check if any of the detected libraries make sense
		foundPnpmLibs := false
		for _, ls := range libraryScanners {
			if ls.Type != "" && ls.Type != ftypes.Npm && ls.Type != ftypes.Yarn {
				foundPnpmLibs = true
				t.Logf("Detected library type: %s", ls.Type)
			}
		}
		if !foundPnpmLibs {
			t.Logf("No PNPM-specific libraries detected (PNPM not supported)")
		}
	}
}

// testMissingPnpmInLibraryMap verifies PNPM is not in the library map
func testMissingPnpmInLibraryMap(t *testing.T) {
	// Check that pnpm-lock.yaml is NOT in the LibraryMap
	if _, ok := models.LibraryMap["pnpm-lock.yaml"]; ok {
		t.Error("PNPM is in LibraryMap but should not be - indicates bug fix applied")
	} else {
		t.Logf("Confirmed: pnpm-lock.yaml is not in LibraryMap (expected failure)")
	}

	// Also check for .NET ecosystem support
	hasNuGetSupport := false
	for filename, libType := range models.LibraryMap {
		if libType == ".net" {
			hasNuGetSupport = true
			t.Logf("Found .NET support: %s -> %s", filename, libType)
		}
	}
	if !hasNuGetSupport {
		t.Error(".NET ecosystem not supported - this is a problem")
	}
}

// testTrivyDBClientInitFailure tests that the current Trivy DB client init fails
// with missing required parameters
func testTrivyDBClientInitFailure(t *testing.T) {
	// The issue: db.NewClient() signature has changed in newer Trivy versions
	// The current code calls: db.NewClient(cacheDir, quiet)
	// But newer versions require additional parameters (e.g., repository, client type)

	// We simulate the error by checking if we can instantiate the client
	// with the old signature - this should fail with newer Trivy

	// This test documents that the current implementation:
	// detector/library.go:66 calls: client := db.NewClient(cacheDir, quiet)
	// But the Trivy API has changed and expects additional required parameters

	// Expected: This would fail at runtime when called
	t.Logf("Testing Trivy DB client initialization...")
	t.Logf("Current code: db.NewClient(cacheDir, quiet)")
	t.Logf("Issue: Missing required parameter(s) in NewClient call")
	t.Logf("Expected: NewClient() call fails due to incompatible signature")

	// Verify the issue exists in detector/library.go
	// by checking the import statement and expected API
	t.Logf("detector/library.go imports: github.com/aquasecurity/trivy/pkg/db")
	t.Logf("This module likely expects different parameters in NewClient()")
}

// testIncompleteScanScopeControl verifies that analyzer scope control is incomplete
func testIncompleteScanScopeControl(t *testing.T) {
	// Create a simple test file to analyze
	testContent := []byte(`{
  "name": "test-package",
  "version": "1.0.0"
}`)

	libFilemap := map[string]scanner.LibFile{
		"package.json": {
			Contents: testContent,
			Filemode: 0644,
		},
	}

	// Test the AnalyzeLibraries function with disabled analyzers
	// The issue: Some analyzers may not be properly disabled during library scans
	// This can cause non-library analyzers (secrets, licenses, OS packages) to run

	libraryScanners, err := scanner.AnalyzeLibraries(context.Background(), libFilemap, false)
	if err != nil {
		t.Logf("Analysis error (may be expected if scope control is incomplete): %v", err)
	}

	// The test is checking that when we analyze lockfiles:
	// 1. Only language library analyzers should run
	// 2. OS package analyzers should be disabled
	// 3. Secret/license analyzers should be disabled
	// 4. But current code may have gaps in what's disabled

	t.Logf("Analyzed %d library scanners from package.json", len(libraryScanners))
	t.Logf("Checking if scope control is complete...")

	// Verify the disabled analyzers list in scanner.AnalyzeLibraries
	// Expected disabled analyzers include:
	expectedDisabled := []analyzer.Type{
		analyzer.TypeAlpine,
		analyzer.TypeDebian,
		analyzer.TypeSecret,
		analyzer.TypeYaml,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
	}

	t.Logf("Expected disabled analyzer count: %d", len(expectedDisabled))

	// The issue is that some new analyzer types may not be in the disabled list
	// For example, TypeLicense or other new types added in newer Trivy versions
	t.Logf("Testing if all non-library analyzers are properly disabled...")
	t.Logf("Issue: Some analyzer types may not be in the disabledAnalyzers list")
	t.Logf("This can cause unnecessary analyzers to run during library scans")
}

// LibFile mirrors the scanner.LibFile struct for testing
// This is needed because the actual struct might not be exported
type LibFile struct {
	Contents []byte
	Filemode os.FileMode
}

// DummyFileInfo for testing purposes
type DummyFileInfo struct {
	size     int64
	filemode os.FileMode
}

func (d *DummyFileInfo) Name() string                     { return "dummy" }
func (d *DummyFileInfo) Size() int64                       { return d.size }
func (d *DummyFileInfo) Mode() os.FileMode                { return d.filemode }
func (d *DummyFileInfo) ModTime() interface{}             { return nil }
func (d *DummyFileInfo) IsDir() bool                       { return false }
func (d *DummyFileInfo) Sys() interface{}                  { return nil }

// TestTrivyImportPaths tests that Trivy imports are using correct paths
func TestTrivyImportPaths(t *testing.T) {
	// The issue: Trivy OS analyzer reference has moved to a new module location
	// detector/library.go uses these imports:
	// "github.com/aquasecurity/trivy/pkg/db"
	// "github.com/aquasecurity/trivy/pkg/log"
	// But these paths may have changed in newer Trivy versions

	// This test documents the import paths used
	t.Logf("Checking Trivy imports...")
	t.Logf("detector/library.go imports:")
	t.Logf("  - github.com/aquasecurity/trivy-db/pkg/db")
	t.Logf("  - github.com/aquasecurity/trivy-db/pkg/metadata")
	t.Logf("  - github.com/aquasecurity/trivy/pkg/db")
	t.Logf("  - github.com/aquasecurity/trivy/pkg/log")

	// The issue would manifest as:
	// 1. Compilation error if imports have changed
	// 2. Runtime error if API signatures have changed

	t.Logf("Expected issue: OS analyzer import path has changed in newer Trivy")
	t.Logf("Current imports may be stale and cause build failures")
}

// TestLibraryScannerEcosystemCoverage tests that all required ecosystems are supported
func TestLibraryScannerEcosystemCoverage(t *testing.T) {
	requiredEcosystems := []struct {
		name       string
		lockFile   string
		ecosystem  string
	}{
		{"Node.js (npm)", "package-lock.json", "node"},
		{"Node.js (yarn)", "yarn.lock", "node"},
		{"Python (pip)", "requirements.txt", "python"},
		{"Python (Poetry)", "poetry.lock", "python"},
		{"Ruby", "Gemfile.lock", "ruby"},
		{"Rust", "Cargo.lock", "rust"},
		{"PHP", "composer.lock", "php"},
		{"Java", "pom.xml", "java"},
		{"Go", "go.mod", "gomod"},
		{".NET (NuGet)", "packages.lock.json", ".net"},
		{"PNPM", "pnpm-lock.yaml", "node"}, // Expected to fail
	}

	for _, tc := range requiredEcosystems {
		if ecosystem, ok := models.LibraryMap[tc.lockFile]; ok {
			if ecosystem != tc.ecosystem {
				t.Errorf("%s: expected ecosystem %s, got %s", tc.name, tc.ecosystem, ecosystem)
			} else {
				t.Logf("✓ %s is supported", tc.name)
			}
		} else {
			t.Logf("✗ %s (%s) is NOT supported in LibraryMap", tc.name, tc.lockFile)
		}
	}
}

// TestAnalyzerDisabledTypes tests that all non-library analyzers are disabled
func TestAnalyzerDisabledTypes(t *testing.T) {
	// The expected disabled analyzers in AnalyzeLibraries function
	// Based on scanner/base.go lines 666-689

	disabledAnalyzersInfo := map[string]string{
		"TypeAlpine":        "OS analyzer - should be disabled",
		"TypeAlma":          "OS analyzer - should be disabled",
		"TypeAmazon":        "OS analyzer - should be disabled",
		"TypeDebian":        "OS analyzer - should be disabled",
		"TypePhoton":        "OS analyzer - should be disabled",
		"TypeCentOS":        "OS analyzer - should be disabled",
		"TypeFedora":        "OS analyzer - should be disabled",
		"TypeOracle":        "OS analyzer - should be disabled",
		"TypeRedHatBase":    "OS analyzer - should be disabled",
		"TypeRocky":         "OS analyzer - should be disabled",
		"TypeSUSE":          "OS analyzer - should be disabled",
		"TypeUbuntu":        "OS analyzer - should be disabled",
		"TypeApk":           "OS analyzer - should be disabled",
		"TypeDpkg":          "OS analyzer - should be disabled",
		"TypeRpm":           "OS analyzer - should be disabled",
		"TypeApkCommand":    "Command analyzer - should be disabled",
		"TypeYaml":          "Config analyzer - should be disabled",
		"TypeTOML":          "Config analyzer - should be disabled",
		"TypeJSON":          "Config analyzer - should be disabled",
		"TypeDockerfile":    "Container analyzer - should be disabled",
		"TypeHCL":           "IaC analyzer - should be disabled",
